17	// RBTD Theurge — test orchestrator entry point
18	//
19	// Subcommands:
20	//   rbtd <manifest> <fixture>
21	//     Suite runner — verify manifest, charge, run all cases, quench.
22	//   rbtd single <manifest> <fixture> [case]
23	//     Single-case runner — no charge/quench. List cases or run one.
24	
25	use std::process::ExitCode;
26	
27	use rbtd::rbtdrc_crucible::{
28	    rbtdrc_lookup_fixture, rbtdrc_set_context, rbtdrc_take_context, RBTDRC_FIXTURES,
29	};
30	use rbtd::rbtdre_engine::{
31	    rbtdre_detect_colors, rbtdre_find_case, rbtdre_list_cases, rbtdre_print_summary,
32	    rbtdre_run_fixture, rbtdre_run_single_case,
33	};
34	use rbtd::rbtdri_invocation::{rbtdri_Context, rbtdri_invoke_global};
35	use rbtd::rbtdrm_manifest::{rbtdrm_verify, RBTDRM_COLOPHON_CRUCIBLE_ACTIVE};
36	
37	fn main() -> ExitCode {
38	    let args: Vec<String> = std::env::args().collect();
39	
40	    if args.get(1).map(|s| s.as_str()) == Some("single") {
41	        return run_single(&args[2..]);
42	    }
43	
44	    run_suite(&args[1..])
45	}
46	
47	// ── Suite runner ─────────────────────────────────────────────
48	
49	fn run_suite(args: &[String]) -> ExitCode {
50	    let manifest = match args.first() {
51	        Some(m) => m,
52	        None => {
53	            eprintln!(
54	                "rbtd: usage: rbtd <manifest> <fixture>\n\
55	                 theurge must be launched via tabtarget (e.g. tt/rbtd-r.FixtureRun.tadmor.sh)"
56	            );
57	            return ExitCode::FAILURE;
58	        }
59	    };
60	
61	    let fixture = match args.get(1) {
62	        Some(n) => n,
63	        None => {
64	            eprintln!("rbtd: no fixture argument — which test fixture to run?");
65	            return ExitCode::FAILURE;
66	        }
67	    };
68	
69	    if let Err(msg) = rbtdrm_verify(manifest, fixture) {
70	        eprintln!("{}", msg);
71	        return ExitCode::FAILURE;
72	    }
73	
74	    let project_root = match std::env::current_dir() {
75	        Ok(p) => p,
76	        Err(e) => {
77	            eprintln!("rbtd: cannot determine working directory: {}", e);
78	            return ExitCode::FAILURE;
79	        }
80	    };
81	
82	    let root_temp = std::env::temp_dir().join(format!("rbtd-{}", std::process::id()));
83	    if let Err(e) = std::fs::create_dir_all(&root_temp) {
84	        eprintln!("rbtd: failed to create temp dir: {}", e);
85	        return ExitCode::FAILURE;
86	    }
87	
88	    let burv_root = root_temp.join("burv");
89	    let ctx = rbtdri_Context::new(&project_root, fixture, &burv_root);
90	
91	    let fixture_def = match rbtdrc_lookup_fixture(fixture) {
92	        Some(f) => f,
93	        None => {
94	            eprintln!(
95	                "rbtd: fixture '{}' has no registered Fixture — \
96	                 manifest verification accepted the name but no Fixture static is bound. \
97	                 Update rbtdrc_lookup_fixture in rbtdrc_crucible.rs.",
98	                fixture
99	            );
100	            return ExitCode::FAILURE;
101	        }
102	    };
103	
104	    rbtdrc_set_context(ctx);
105	
106	    let colors = rbtdre_detect_colors();
107	    let run_result = rbtdre_run_fixture(fixture_def, &colors, &root_temp);
108	
109	    let _ctx = rbtdrc_take_context();
110	
111	    let result = match run_result {
112	        Ok(r) => r,
113	        Err(msg) => {
114	            eprintln!("rbtd: {}", msg);
115	            return ExitCode::FAILURE;
116	        }
117	    };
118	
119	    rbtdre_print_summary(&result, &colors);
120	
121	    if result.failed > 0 {
122	        eprintln!("rbtd: {} case(s) failed", result.failed);
123	        ExitCode::FAILURE
124	    } else {
125	        ExitCode::SUCCESS
126	    }
127	}
128	
129	// ── Single-case runner ───────────────────────────────────────
130	
131	fn run_single(args: &[String]) -> ExitCode {
132	    let manifest = match args.first() {
133	        Some(m) => m,
134	        None => {
135	            eprintln!(
136	                "rbtd single: usage: rbtd single <manifest> <fixture> [case]\n\
137	                 omit case to list all cases for the fixture"
138	            );
139	            return ExitCode::FAILURE;
140	        }
141	    };
142	
143	    let fixture = match args.get(1) {
144	        Some(f) => f,
145	        None => {
146	            eprintln!("rbtd single: no fixture argument");
147	            list_fixtures();
148	            return ExitCode::FAILURE;
149	        }
150	    };
151	
152	    if !RBTDRC_FIXTURES.iter().any(|f| f.name == *fixture) {
153	        eprintln!("rbtd single: unknown fixture '{}'", fixture);
154	        list_fixtures();
155	        return ExitCode::FAILURE;
156	    }
157	
158	    if let Err(msg) = rbtdrm_verify(manifest, fixture) {
159	        eprintln!("{}", msg);
160	        return ExitCode::FAILURE;
161	    }
162	
163	    // Set up execution context early — needed for charge check and case execution
164	    let project_root = match std::env::current_dir() {
165	        Ok(p) => p,
166	        Err(e) => {
167	            eprintln!("rbtd: cannot determine working directory: {}", e);
168	            return ExitCode::FAILURE;
169	        }
170	    };
171	
172	    let root_temp = std::env::temp_dir().join(format!("rbtd-{}", std::process::id()));
173	    if let Err(e) = std::fs::create_dir_all(&root_temp) {
174	        eprintln!("rbtd: failed to create temp dir: {}", e);
175	        return ExitCode::FAILURE;
176	    }
177	
178	    // Context is required for every case execution path (rbtdrc_with_ctx).
179	    // Fixtures with a setup hook (crucible charge) additionally verify their
180	    // crucible is charged externally — single-case mode never charges.
181	    let burv_root = root_temp.join("burv");
182	    let mut ctx = rbtdri_Context::new(&project_root, fixture, &burv_root);
183	
184	    let fixture_def = match rbtdrc_lookup_fixture(fixture) {
185	        Some(f) => f,
186	        None => {
187	            eprintln!(
188	                "rbtd single: fixture '{}' has no registered Fixture",
189	                fixture
190	            );
191	            return ExitCode::FAILURE;
192	        }
193	    };
194	
195	    if fixture_def.setup.is_some() {
196	        match rbtdri_invoke_global(
197	            &mut ctx,
198	            RBTDRM_COLOPHON_CRUCIBLE_ACTIVE,
199	            &[fixture],
200	            &[],
201	        ) {
202	            Ok(r) if r.exit_code == 0 => {}
203	            _ => {
204	                eprintln!(
205	                    "rbtd single: crucible not charged for '{}'\n\
206	                     charge first: tt/rbw-cC.Charge.{}.sh",
207	                    fixture, fixture
208	                );
209	                return ExitCode::FAILURE;
210	            }
211	        }
212	    }
213	
214	    rbtdrc_set_context(ctx);
215	
216	    let cases = fixture_def.cases;
217	
218	    // No case argument — list all cases
219	    let case_name = match args.get(2) {
220	        None => {
221	            rbtdre_list_cases(cases);
222	            return ExitCode::SUCCESS;
223	        }
224	        Some(n) => n,
225	    };
226	
227	    // Find the case
228	    let case = match rbtdre_find_case(cases, case_name) {
229	        Some(c) => c,
230	        None => {
231	            eprintln!(
232	                "rbtd single: case '{}' not found in fixture '{}'",
233	                case_name, fixture
234	            );
235	            rbtdre_list_cases(cases);
236	            return ExitCode::FAILURE;
237	        }
238	    };
239	
240	    let colors = rbtdre_detect_colors();
241	    let result = match rbtdre_run_single_case(case, &colors, &root_temp) {
242	        Ok(r) => r,
243	        Err(msg) => {
244	            eprintln!("rbtd: case execution error: {}", msg);
245	            return ExitCode::FAILURE;
246	        }
247	    };
248	
249	    rbtdre_print_summary(&result, &colors);
250	
251	    if result.failed > 0 {
252	        ExitCode::FAILURE
253	    } else {
254	        ExitCode::SUCCESS
255	    }
256	}
257	
258	fn list_fixtures() {
259	    eprintln!("available fixtures:");
260	    for f in RBTDRC_FIXTURES {
261	        eprintln!("  {}", f.name);
262	    }
263	}
