45	// ── Thread-local invocation context ──────────────────────────
46	
47	/// Ifrit binary name inside the bottle container.
48	const RBTDRC_IFRIT_BINARY: &str = "rbid";
49	
50	/// Test connectivity target — ICANN-owned, stable single /20 CIDR (192.0.32.0/20)
51	const RBTDRC_CONNECTIVITY_DOMAIN: &str = "www.internic.net";
52	
53	thread_local! {
54	    static RBTDRC_CTX: RefCell<Option<rbtdri_Context>> = RefCell::new(None);
55	}
56	
57	/// Store invocation context for case functions. Called before run_sections.
58	pub fn rbtdrc_set_context(ctx: rbtdri_Context) {
59	    RBTDRC_CTX.with(|c| *c.borrow_mut() = Some(ctx));
60	}
61	
62	/// Retrieve invocation context after cases complete. Called for quench.
63	pub fn rbtdrc_take_context() -> rbtdri_Context {
64	    RBTDRC_CTX.with(|c| {
65	        c.borrow_mut()
66	            .take()
67	            .expect("rbtdrc: no context — was rbtdrc_set_context called?")
68	    })
69	}
70	
71	pub(crate) fn rbtdrc_with_ctx<F>(f: F) -> rbtdre_Verdict
72	where
73	    F: FnOnce(&mut rbtdri_Context) -> rbtdre_Verdict,
74	{
75	    RBTDRC_CTX.with(|c| {
76	        let mut opt = c.borrow_mut();
77	        let ctx = opt
78	            .as_mut()
79	            .expect("rbtdrc: no invocation context for case execution");
80	        f(ctx)
81	    })
82	}
83	
84	// ── Crucible lifecycle hooks (setup/teardown) ────────────────
85	
86	/// Setup hook for crucible fixtures: charge → CrucibleActive assertion.
87	/// Reads ctx from thread-local. Returns Err on any step failure; engine
88	/// surfaces this as a fixture failure and runs teardown anyway.
89	///
90	/// Service-readiness waits are folded into the charge tabtarget itself,
91	/// driven by the per-nameplate `RBRN_BOTTLE_READINESS_DELAY_SEC` fact.
92	pub fn rbtdrc_charge_crucible() -> Result<(), String> {
93	    RBTDRC_CTX.with(|c| {
94	        let mut opt = c.borrow_mut();
95	        let ctx = opt
96	            .as_mut()
97	            .ok_or_else(|| "rbtdrc: no invocation context for charge".to_string())?;
98	        zrbtdrc_charge_impl(ctx)
99	    })
100	}
101	
102	/// Teardown hook for crucible fixtures: quench → inverse CrucibleActive
103	/// assertion. Reads ctx from thread-local. Best-effort — surfaces failures as
104	/// stderr warnings rather than errors; teardown always completes.
105	pub fn rbtdrc_quench_crucible() {
106	    RBTDRC_CTX.with(|c| {
107	        let mut opt = c.borrow_mut();
108	        if let Some(ctx) = opt.as_mut() {
109	            zrbtdrc_quench_impl(ctx);
110	        } else {
111	            eprintln!("Warning: rbtdrc: no invocation context for quench — skipped");
112	        }
113	    });
114	}
115	
116	fn zrbtdrc_charge_impl(ctx: &mut rbtdri_Context) -> Result<(), String> {
117	    let fixture = ctx.fixture().to_string();
118	    eprintln!("\nCharging crucible for nameplate '{}'...", fixture);
119	    match rbtdri_invoke(ctx, RBTDRM_COLOPHON_CHARGE, &[]) {
120	        Ok(r) if r.exit_code == 0 => {
121	            eprintln!("Crucible charged");
122	        }
123	        Ok(r) => {
124	            return Err(format!("Charge failed (exit {})\n{}", r.exit_code, r.stderr));
125	        }
126	        Err(e) => {
127	            return Err(format!("Charge invocation failed: {}", e));
128	        }
129	    }
130	
131	    eprintln!("Verifying crucible is active after charge...");
132	    match rbtdri_invoke_global(ctx, RBTDRM_COLOPHON_CRUCIBLE_ACTIVE, &[&fixture], &[]) {
133	        Ok(r) if r.exit_code == 0 => {
134	            eprintln!("Crucible active confirmed");
135	        }
136	        Ok(r) => {
137	            return Err(format!(
138	                "Lifecycle assertion failed: crucible not active after charge (exit {})\n{}",
139	                r.exit_code, r.stderr
140	            ));
141	        }
142	        Err(e) => {
143	            return Err(format!(
144	                "CrucibleActive invocation failed after charge: {}",
145	                e
146	            ));
147	        }
148	    }
149	
150	    Ok(())

